onClick:
{{
  (async () => {
    JSutils.resetInactivityTimer();

    const isInsert = appsmith.store.modalContexto?.acaoTipo === "ADICIONAR";
    const query = isInsert ? InsertParticularidadesPet : UpdateParticularidadesPet;

    const currentID = isInsert ? null : (
      appsmith.store.particularidadeSelecionada?.par002_id || 
      TableParticularidades.selectedRow?.par002_id || 
      InputID.text
    );

    const params = {
      par002_par001_id: Select1Particularidade.selectedOptionValue,
      par002_descricao: (InputDescParticular.text || "").trim().toUpperCase(),
      par002_alerta: Switch1Atencao.isSwitchedOn ? 'S' : 'N',
      par002_ani002_id: appsmith.store.petID_Particularidades,
      par002_id: currentID 
    };

    try {
      const response = await query.run(params);

      // Se for Insert, pegamos o ID que o banco acabou de gerar (RETURNING par002_id)
      // Se for Update, usamos o currentID que já tínhamos
      const idParaSelecionar = isInsert ? response[0].par002_id : currentID;

      // SALVAMOS O ID NO STORE PARA A TABELA USAR
      await storeValue('idSelecionadoPART', idParaSelecionar);

      showAlert(`Particularidade ${isInsert ? 'incluída' : 'atualizada'} com sucesso!`, "success");

      // Atualiza a lista
      await SelectParticularidadesPET.run();

    } catch (err) {
      showAlert("Erro ao salvar: " + err.message, "error");
    }
  })()
}}
